mapper.select:
-- 공복식후 혈당 평균
WITH -- 1) 기간 내 모든 끼니 시각 목록(한 끼니 = 한 행) meals AS ( SELECT DISTINCT STR_TO_DATE(CONCAT(b.EAT_DATE, b.EAT_STIME), '%Y%m%d%H%i%s') AS meal_ts FROM T_FOOD_TRAN b WHERE b.USER_UUID = #{userId} AND STR_TO_DATE(CONCAT(b.EAT_DATE, b.EAT_STIME), '%Y%m%d%H%i%s') >= #{date} - INTERVAL 24 HOUR AND STR_TO_DATE(CONCAT(b.EAT_DATE, b.EAT_STIME), '%Y%m%d%H%i%s') < #{date} ),
-- 기간 평균(백업용) avg24h AS ( SELECT AVG(a.UPT_VALUE) AS avg_val FROM T_BLDINF_TRAN a WHERE a.USER_UUID = #{userId} AND a.UPT_VALUE > 0 AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') >= #{date} - INTERVAL 24 HOUR AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') < #{date} ),
/* ---- 공복(03:00~06:00) 평균 ---- */ fasting_window_avg AS ( SELECT AVG(a.UPT_VALUE) AS val FROM T_BLDINF_TRAN a WHERE a.USER_UUID = #{userId} AND a.UPT_VALUE > 0 AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') >= #{date} - INTERVAL 24 HOUR AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') < #{date} AND TIME(STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s')) >= '03:00:00' AND TIME(STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s')) < '06:00:00' -- 06:00 미포함 ),
/* ---- 식후 2시간 이후 '가장 빠른 것' 선택 ---- */ after2h_candidates AS ( SELECT m.meal_ts, a.UPT_VALUE, STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') AS cgm_ts, ROW_NUMBER() OVER ( PARTITION BY m.meal_ts ORDER BY STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') ASC ) AS rn FROM meals m JOIN T_BLDINF_TRAN a ON a.USER_UUID = #{userId} AND a.UPT_VALUE > 0 AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') >= m.meal_ts + INTERVAL 2 HOUR -- 기간(최근 24시간) 안에서만 계산 AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') >= #{date} - INTERVAL 24 HOUR AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') < #{date} ), after2h_vals AS ( SELECT meal_ts, UPT_VALUE FROM after2h_candidates WHERE rn = 1 -- 끼니별 '가장 이른(가장 빠른)' 1건 ), after2h_avg AS ( SELECT AVG(UPT_VALUE) AS val FROM after2h_vals ),
-- 끼니 유무 판단 meal_cnt AS ( SELECT COUNT(*) AS cnt FROM meals )
SELECT -- 공복값: 03:00~06:00 평균, 없으면 기간 평균 COALESCE((SELECT val FROM fasting_window_avg), (SELECT avg_val FROM avg24h)) AS fastingValue, -- 식후값: 끼니 없으면 기간 평균, 있으면 끼니별 '가장 빠른' 값들의 평균(없으면 기간 평균) CASE WHEN (SELECT cnt FROM meal_cnt) = 0 THEN (SELECT avg_val FROM avg24h) ELSE COALESCE((SELECT val FROM after2h_avg), (SELECT avg_val FROM avg24h)) END AS after2hValue;

-- 공복식후 혈당 평균
WITH -- 1) 기간 내 모든 끼니 시각 목록(한 끼니 = 한 행) meals AS ( SELECT DISTINCT STR_TO_DATE(CONCAT(b.EAT_DATE, b.EAT_STIME), '%Y%m%d%H%i%s') AS meal_ts FROM T_FOOD_TRAN b WHERE b.USER_UUID = #{userId} AND STR_TO_DATE(CONCAT(b.EAT_DATE, b.EAT_STIME), '%Y%m%d%H%i%s') >= CONCAT(#{start}, ' 00:00:00') AND STR_TO_DATE(CONCAT(b.EAT_DATE, b.EAT_STIME), '%Y%m%d%H%i%s') < DATE_ADD(#{end}, INTERVAL 1 DAY) ),
-- 기간 평균(백업용) avg24h AS ( SELECT AVG(a.UPT_VALUE) AS avg_val FROM T_BLDINF_TRAN a WHERE a.USER_UUID = #{userId} AND a.UPT_VALUE > 0 AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') >= CONCAT(#{start}, ' 00:00:00') AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') < DATE_ADD(#{end}, INTERVAL 1 DAY) ),
/* ---- 공복(03:00~06:00) 평균 ---- */ fasting_window_avg AS ( SELECT AVG(a.UPT_VALUE) AS val FROM T_BLDINF_TRAN a WHERE a.USER_UUID = #{userId} AND a.UPT_VALUE > 0 AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') >= CONCAT(#{start}, ' 00:00:00') AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') < DATE_ADD(#{end}, INTERVAL 1 DAY) AND TIME(STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s')) >= '03:00:00' AND TIME(STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s')) < '06:00:00' -- 06:00 미포함 ),
/* ---- 식후 2시간 이후(가장 이른 시각 = 1위) ---- */ after2h_candidates AS ( SELECT m.meal_ts, a.UPT_VALUE, STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') AS cgm_ts, ROW_NUMBER() OVER ( PARTITION BY m.meal_ts ORDER BY STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') ASC ) AS rn FROM meals m JOIN T_BLDINF_TRAN a ON a.USER_UUID = #{userId} AND a.UPT_VALUE > 0 AND STR_TO_DATE(a.CGM_DTM, '%Y-%m-%d %H:%i:%s') >= m.meal_ts + INTERVAL 2 HOUR ), after2h_vals AS ( SELECT meal_ts, UPT_VALUE FROM after2h_candidates WHERE rn = 1 ), after2h_avg AS ( SELECT AVG(UPT_VALUE) AS val FROM after2h_vals ),
-- 끼니 유무 판단 meal_cnt AS ( SELECT COUNT(*) AS cnt FROM meals )
SELECT -- 공복값: 03:00~06:00 평균, 없으면 기간 평균 COALESCE((SELECT val FROM fasting_window_avg), (SELECT avg_val FROM avg24h)) AS fastingValue, -- 식후값: 끼니 없으면 기간 평균, 있으면 식후 평균(없으면 기간 평균) CASE WHEN (SELECT cnt FROM meal_cnt) = 0 THEN (SELECT avg_val FROM avg24h) ELSE COALESCE((SELECT val FROM after2h_avg), (SELECT avg_val FROM avg24h)) END AS after2hValue;

WITH MEALS AS ( SELECT USER_UUID, EAT_DATE, EAT_STIME, FOOD_NAME, FOOD_CNT, -- STORED 컬럼(EAT_DT)이 있으면 그걸 사용 STR_TO_DATE(CONCAT(EAT_DATE, LPAD(EAT_STIME, 6, '0')), '%Y%m%d%H%i%s') AS eat_dt FROM T_FOOD_TRAN WHERE user_uuid = #{userId} -- 가능하면 바인드에서 YYYYMMDD 로 넘겨 함수 제거 AND EAT_DATE >= REPLACE(LEFT(#{start}, 10), '-', '') AND EAT_DATE <= REPLACE(LEFT(#{end}, 10), '-', '') ),
/* PRE/POST 둘 다: 각 식사행에 대해 '인덱스 범위 → 정렬방향 → LIMIT 1'로 직진 탐색 */ ENRICHED AS ( SELECT m.USER_UUID, m.EAT_DATE, m.EAT_STIME, m.FOOD_NAME, m.FOOD_CNT, m.eat_dt, pre.CGM_DTM AS CGM_BEFORE_NEAREST, pre.UPT_VALUE AS UPT_VALUE_BEFORE, post.CGM_DTM AS CGM_AFTER_2H_NEAREST, post.UPT_VALUE AS UPT_VALUE_AFTER_2H FROM MEALS m /* 식사 직전: m.eat_dt 이하에서 가장 최근 */ LEFT JOIN LATERAL ( SELECT b.CGM_DTM, b.UPT_VALUE FROM T_BLDINF_TRAN b WHERE b.user_uuid = m.user_uuid AND b.CGM_DTM <= m.eat_dt ORDER BY b.CGM_DTM DESC LIMIT 1 ) pre ON TRUE
/* 식사 2시간 후: m.eat_dt + 2h 이상에서 가장 이른 */ LEFT JOIN LATERAL ( SELECT b.CGM_DTM, b.UPT_VALUE FROM T_BLDINF_TRAN b WHERE b.user_uuid = m.user_uuid AND b.CGM_DTM >= m.eat_dt + INTERVAL 2 HOUR ORDER BY b.CGM_DTM ASC LIMIT 1 ) post ON TRUE )
, MATCHED AS ( SELECT e.USER_UUID, e.EAT_DATE, e.FOOD_NAME, e.FOOD_CNT, DATE_FORMAT(STR_TO_DATE(LPAD(e.EAT_STIME, 6, '0'), '%H%i%s'), '%H:%i') AS EAT_STIME, e.CGM_BEFORE_NEAREST, e.UPT_VALUE_BEFORE, e.CGM_AFTER_2H_NEAREST, e.UPT_VALUE_AFTER_2H, (e.UPT_VALUE_AFTER_2H - e.UPT_VALUE_BEFORE) AS DELTA_2H FROM ENRICHED e WHERE e.UPT_VALUE_BEFORE IS NOT NULL AND e.UPT_VALUE_AFTER_2H IS NOT NULL )
, DEDUP AS ( SELECT *, ROW_NUMBER() OVER ( PARTITION BY USER_UUID, FOOD_NAME ORDER BY DELTA_2H DESC, CGM_AFTER_2H_NEAREST ASC ) AS food_rn FROM MATCHED )
SELECT ROW_NUMBER() OVER (ORDER BY DELTA_2H DESC) AS RN, USER_UUID, EAT_DATE, FOOD_NAME, FOOD_CNT, EAT_STIME, CGM_BEFORE_NEAREST, UPT_VALUE_BEFORE, CGM_AFTER_2H_NEAREST, UPT_VALUE_AFTER_2H, DELTA_2H FROM DEDUP WHERE food_rn = 1 ORDER BY DELTA_2H DESC LIMIT 3;

WITH meals AS ( SELECT USER_UUID, STR_TO_DATE(CONCAT(EAT_DATE, EAT_ETIME), '%Y%m%d%H%i%s') AS start_ts, DATE(STR_TO_DATE(CONCAT(EAT_DATE, EAT_ETIME), '%Y%m%d%H%i%s')) AS meal_date FROM T_FOOD_TRAN WHERE USER_UUID = #{userId}
GROUP BY USER_UUID, start_ts, meal_date ), meal_foods AS ( SELECT USER_UUID, STR_TO_DATE(CONCAT(EAT_DATE, EAT_ETIME), '%Y%m%d%H%i%s') AS start_ts, GROUP_CONCAT(DISTINCT FOOD_NAME ORDER BY FOOD_NAME SEPARATOR ', ') AS foods_in_meal FROM T_FOOD_TRAN WHERE USER_UUID = #{userId} GROUP BY USER_UUID, start_ts ),
daily_foods AS ( SELECT USER_UUID, DATE(STR_TO_DATE(CONCAT(EAT_DATE, EAT_ETIME), '%Y%m%d%H%i%s')) AS meal_date, GROUP_CONCAT(DISTINCT FOOD_NAME ORDER BY FOOD_NAME SEPARATOR ', ') AS foods_in_day FROM T_FOOD_TRAN WHERE USER_UUID = #{userId} GROUP BY USER_UUID, meal_date ), pre_ranked AS ( SELECT m.USER_UUID, m.start_ts, m.meal_date, b.CGM_DTM, b.UPT_VALUE, ROW_NUMBER() OVER ( PARTITION BY m.USER_UUID, m.start_ts ORDER BY b.CGM_DTM DESC ) AS rn FROM meals m JOIN T_BLDINF_TRAN b ON b.USER_UUID = m.USER_UUID AND b.UPT_VALUE > 0 AND b.CGM_DTM < m.start_ts ), post_ranked AS ( SELECT m.USER_UUID, m.start_ts, m.meal_date, b.CGM_DTM, b.UPT_VALUE, ROW_NUMBER() OVER ( PARTITION BY m.USER_UUID, m.start_ts ORDER BY b.CGM_DTM DESC ) AS rn FROM meals m JOIN T_BLDINF_TRAN b ON b.USER_UUID = m.USER_UUID AND b.UPT_VALUE > 0 AND b.CGM_DTM BETWEEN STR_TO_DATE(DATE(#{start}), '%Y-%m-%d') AND DATE_ADD(STR_TO_DATE(DATE(#{end}), '%Y-%m-%d'), INTERVAL 1 DAY) - INTERVAL 1 SECOND ), pre_picked AS ( SELECT USER_UUID, start_ts, meal_date, CGM_DTM AS pre_time, UPT_VALUE AS pre_value FROM pre_ranked WHERE rn = 1 ), post_picked AS ( SELECT USER_UUID, start_ts, meal_date, CGM_DTM AS post_time, UPT_VALUE AS post_value FROM post_ranked WHERE rn = 1 ), per_meal AS ( SELECT m.USER_UUID, m.meal_date AS foodDate, DATE_FORMAT(m.start_ts, '%Y-%m-%d %H:%i:%s') AS start_ts, f.foods_in_meal AS foodName, DATE_FORMAT(pre.pre_time, '%Y-%m-%d %H:%i:%s') AS pre_time, pre.pre_value, DATE_FORMAT(post.post_time, '%Y-%m-%d %H:%i:%s') AS post_time, post.post_value, (post.post_value - pre.pre_value) AS foodValue, ROUND( (post.post_value - pre.pre_value) / NULLIF(pre.pre_value,0) * 100, 1 ) AS delta_pct FROM meals m LEFT JOIN meal_foods f ON f.USER_UUID = m.USER_UUID AND f.start_ts = m.start_ts LEFT JOIN pre_picked pre ON pre.USER_UUID = m.USER_UUID AND pre.start_ts = m.start_ts LEFT JOIN post_picked post ON post.USER_UUID = m.USER_UUID AND post.start_ts = m.start_ts WHERE pre.pre_value IS NOT NULL AND post.post_value IS NOT NULL ) SELECT pm.USER_UUID, DATE_FORMAT(pm.foodDate, '%Y-%m-%d') as foodDate , df.foods_in_day, TRUNCATE(AVG(pm.foodValue), 0) AS avg_increase , SUM(pm.foodValue) AS sum_increase, COUNT(*) AS meal_count FROM per_meal pm LEFT JOIN daily_foods df ON df.USER_UUID = pm.USER_UUID AND df.meal_date = pm.foodDate GROUP BY pm.USER_UUID, pm.foodDate, df.foods_in_day ORDER BY CASE WHEN #{gubun} = '1' THEN -avg_increase ELSE avg_increase END ASC, pm.foodDate
